sys_ui_script.script:
var PortalDarkTheme = (function () {

    function applyTheme() {

        var theme = localStorage.getItem("portalTheme") || "light";

        if (theme === "dark") {
            document.body.classList.add("dark-theme");
        } else {
            document.body.classList.remove("dark-theme");
        }
    }

    /* Apply once on load */
    window.addEventListener("load", applyTheme);

    /* Apply after portal navigation */
    document.addEventListener("sp.page.loaded", applyTheme);

    return {
        applyTheme: applyTheme
    };

})();
